    20→#include <portable.h>
    21→
    22→#include "rewrite-int.h"
    23→
    24→/*
    25→ * Compares two cookies
    26→ */
    27→static int
    28→rewrite_cookie_cmp(
    29→                const void *c1,
    30→                const void *c2
    31→)
    32→{
    33→	const struct rewrite_session *s1, *s2;
    34→
    35→	s1 = ( const struct rewrite_session * )c1;
    36→	s2 = ( const struct rewrite_session * )c2;
    37→
    38→	assert( s1 != NULL );
    39→	assert( s2 != NULL );
    40→	assert( s1->ls_cookie != NULL );
    41→	assert( s2->ls_cookie != NULL );
    42→
    43→        return ( ( s1->ls_cookie < s2->ls_cookie ) ? -1 :
    44→			( ( s1->ls_cookie > s2->ls_cookie ) ? 1 : 0 ) );
    45→}
    46→
    47→/*
    48→ * Duplicate cookies?
    49→ */
    50→static int
    51→rewrite_cookie_dup(
    52→                void *c1,
    53→                void *c2
    54→)
    55→{
    56→	struct rewrite_session *s1, *s2;
    57→
    58→	s1 = ( struct rewrite_session * )c1;
    59→	s2 = ( struct rewrite_session * )c2;
    60→	
    61→	assert( s1 != NULL );
    62→	assert( s2 != NULL );
    63→	assert( s1->ls_cookie != NULL );
    64→	assert( s2->ls_cookie != NULL );
    65→	
    66→	assert( s1->ls_cookie != s2->ls_cookie );
    67→	
    68→        return ( ( s1->ls_cookie == s2->ls_cookie ) ? -1 : 0 );
    69→}
    70→
    71→/*
    72→ * Inits a session
    73→ */
    74→struct rewrite_session *
    75→rewrite_session_init(
    76→		struct rewrite_info *info,
    77→		const void *cookie
    78→)
    79→{
    80→	struct rewrite_session 	*session, tmp;
    81→	int			rc;
    82→
    83→	assert( info != NULL );
    84→	assert( cookie != NULL );
    85→
    86→#ifdef USE_REWRITE_LDAP_PVT_THREADS
    87→	ldap_pvt_thread_rdwr_wlock( &info->li_cookies_mutex );
    88→#endif /* USE_REWRITE_LDAP_PVT_THREADS */
    89→
    90→	tmp.ls_cookie = ( void * )cookie;
    91→	session = ( struct rewrite_session * )ldap_avl_find( info->li_cookies, 
    92→			( caddr_t )&tmp, rewrite_cookie_cmp );
    93→	if ( session ) {
    94→		session->ls_count++;
    95→#ifdef USE_REWRITE_LDAP_PVT_THREADS
    96→		ldap_pvt_thread_rdwr_wunlock( &info->li_cookies_mutex );
    97→#endif /* USE_REWRITE_LDAP_PVT_THREADS */
    98→		return session;
    99→	}
   100→		
   101→	session = calloc( sizeof( struct rewrite_session ), 1 );
   102→	if ( session == NULL ) {
   103→#ifdef USE_REWRITE_LDAP_PVT_THREADS
   104→		ldap_pvt_thread_rdwr_wunlock( &info->li_cookies_mutex );
   105→#endif /* USE_REWRITE_LDAP_PVT_THREADS */
   106→		return NULL;
   107→	}
   108→	session->ls_cookie = ( void * )cookie;
   109→	session->ls_count = 1;
   110→	
   111→#ifdef USE_REWRITE_LDAP_PVT_THREADS
   112→	if ( ldap_pvt_thread_mutex_init( &session->ls_mutex ) ) {
   113→		free( session );
   114→		ldap_pvt_thread_rdwr_wunlock( &info->li_cookies_mutex );
   115→		return NULL;
   116→	}
   117→	if ( ldap_pvt_thread_rdwr_init( &session->ls_vars_mutex ) ) {
   118→		ldap_pvt_thread_mutex_destroy( &session->ls_mutex );
   119→		free( session );
   120→		ldap_pvt_thread_rdwr_wunlock( &info->li_cookies_mutex );
   121→		return NULL;
   122→	}
   123→#endif /* USE_REWRITE_LDAP_PVT_THREADS */
   124→
   125→	rc = ldap_avl_insert( &info->li_cookies, ( caddr_t )session,
   126→			rewrite_cookie_cmp, rewrite_cookie_dup );
   127→	info->li_num_cookies++;
   128→
   129→#ifdef USE_REWRITE_LDAP_PVT_THREADS
   130→	ldap_pvt_thread_rdwr_wunlock( &info->li_cookies_mutex );
   131→#endif /* USE_REWRITE_LDAP_PVT_THREADS */
   132→	
   133→	if ( rc != 0 ) {
   134→#ifdef USE_REWRITE_LDAP_PVT_THREADS
   135→		ldap_pvt_thread_rdwr_destroy( &session->ls_vars_mutex );
   136→		ldap_pvt_thread_mutex_destroy( &session->ls_mutex );
   137→#endif /* USE_REWRITE_LDAP_PVT_THREADS */
   138→
   139→		free( session );
   140→		return NULL;
   141→	}
   142→	
   143→	return session;
   144→}
   145→
   146→/*
   147→ * Fetches a session
   148→ */
   149→struct rewrite_session *
   150→rewrite_session_find(
   151→		struct rewrite_info *info,
   152→		const void *cookie
   153→)
   154→{
   155→	struct rewrite_session *session, tmp;
   156→
   157→	assert( info != NULL );
   158→	assert( cookie != NULL );
   159→	
   160→	tmp.ls_cookie = ( void * )cookie;
   161→#ifdef USE_REWRITE_LDAP_PVT_THREADS
   162→	ldap_pvt_thread_rdwr_rlock( &info->li_cookies_mutex );
   163→#endif /* USE_REWRITE_LDAP_PVT_THREADS */
   164→	session = ( struct rewrite_session * )ldap_avl_find( info->li_cookies,
   165→			( caddr_t )&tmp, rewrite_cookie_cmp );
   166→#ifdef USE_REWRITE_LDAP_PVT_THREADS
   167→	if ( session ) {
   168→		ldap_pvt_thread_mutex_lock( &session->ls_mutex );
   169→		session->ls_count++;
   170→	}
   171→	ldap_pvt_thread_rdwr_runlock( &info->li_cookies_mutex );
   172→#endif /* USE_REWRITE_LDAP_PVT_THREADS */
   173→
   174→	return session;
   175→}
   176→
   177→/*
   178→ * Returns a session
   179→ */
   180→void
   181→rewrite_session_return(
   182→		struct rewrite_info *info,
   183→		struct rewrite_session *session
   184→)
   185→{
   186→	assert( session != NULL );
   187→	session->ls_count--;
   188→#ifdef USE_REWRITE_LDAP_PVT_THREADS
   189→	ldap_pvt_thread_mutex_unlock( &session->ls_mutex );
   190→#endif /* USE_REWRITE_LDAP_PVT_THREADS */
   191→}
   192→
   193→/*
   194→ * Defines and inits a var with session scope
   195→ */
   196→int
   197→rewrite_session_var_set_f(
   198→		struct rewrite_info *info,
   199→		const void *cookie,
   200→		const char *name,
   201→		const char *value,
   202→		int flags
   203→)
   204→{
   205→	struct rewrite_session *session;
   206→	struct rewrite_var *var;
   207→
   208→	assert( info != NULL );
   209→	assert( cookie != NULL );
   210→	assert( name != NULL );
   211→	assert( value != NULL );
   212→
   213→	session = rewrite_session_find( info, cookie );
   214→	if ( session == NULL ) {
   215→		session = rewrite_session_init( info, cookie );
   216→		if ( session == NULL ) {
   217→			return REWRITE_ERR;
   218→		}
   219→
   220→#ifdef USE_REWRITE_LDAP_PVT_THREADS
   221→		ldap_pvt_thread_mutex_lock( &session->ls_mutex );
   222→#endif /* USE_REWRITE_LDAP_PVT_THREADS */
   223→	}
   224→
   225→#ifdef USE_REWRITE_LDAP_PVT_THREADS
   226→	ldap_pvt_thread_rdwr_wlock( &session->ls_vars_mutex );
   227→#endif /* USE_REWRITE_LDAP_PVT_THREADS */
   228→
   229→	var = rewrite_var_find( session->ls_vars, name );
   230→	if ( var != NULL ) {
   231→		assert( var->lv_value.bv_val != NULL );
   232→
   233→		(void)rewrite_var_replace( var, value, flags );
   234→
   235→	} else {
   236→		var = rewrite_var_insert_f( &session->ls_vars, name, value, flags );
   237→		if ( var == NULL ) {
   238→#ifdef USE_REWRITE_LDAP_PVT_THREADS
   239→			ldap_pvt_thread_rdwr_wunlock( &session->ls_vars_mutex );
   240→#endif /* USE_REWRITE_LDAP_PVT_THREADS */
   241→			rewrite_session_return( info, session );
   242→			return REWRITE_ERR;
   243→		}
   244→	}	
   245→	
   246→#ifdef USE_REWRITE_LDAP_PVT_THREADS
   247→	ldap_pvt_thread_rdwr_wunlock( &session->ls_vars_mutex );
   248→#endif /* USE_REWRITE_LDAP_PVT_THREADS */
   249→
   250→	rewrite_session_return( info, session );
   251→
   252→	return REWRITE_SUCCESS;
   253→}
   254→
   255→/*
   256→ * Gets a var with session scope
   257→ */
   258→int
   259→rewrite_session_var_get(
   260→		struct rewrite_info *info,
   261→		const void *cookie,
   262→		const char *name,
   263→		struct berval *value
   264→)
   265→{
   266→	struct rewrite_session *session;
   267→	struct rewrite_var *var;
   268→	int rc = REWRITE_SUCCESS;
   269→
   270→	assert( info != NULL );
   271→	assert( cookie != NULL );
   272→	assert( name != NULL );
   273→	assert( value != NULL );
   274→
   275→	value->bv_val = NULL;
   276→	value->bv_len = 0;
   277→	
   278→	if ( cookie == NULL ) {
   279→		return REWRITE_ERR;
   280→	}
   281→
   282→	session = rewrite_session_find( info, cookie );
   283→	if ( session == NULL ) {
   284→		return REWRITE_ERR;
   285→	}
   286→
   287→#ifdef USE_REWRITE_LDAP_PVT_THREADS
   288→	ldap_pvt_thread_rdwr_rlock( &session->ls_vars_mutex );
   289→#endif /* USE_REWRITE_LDAP_PVT_THREADS */
   290→	
   291→	var = rewrite_var_find( session->ls_vars, name );
   292→	if ( var != NULL ) {
   293→		value->bv_val = strdup( var->lv_value.bv_val );
   294→		value->bv_len = var->lv_value.bv_len;
   295→	}
   296→
   297→	if ( var == NULL || value->bv_val == NULL ) {
   298→		rc = REWRITE_ERR;
   299→	}
   300→
   301→#ifdef USE_REWRITE_LDAP_PVT_THREADS
   302→        ldap_pvt_thread_rdwr_runlock( &session->ls_vars_mutex );
   303→#endif /* USE_REWRITE_LDAP_PVT_THREADS */
   304→
   305→	rewrite_session_return( info, session );
   306→
   307→	return rc;
   308→}
   309→
   310→static void
   311→rewrite_session_clean( void *v_session )
   312→{
   313→	struct rewrite_session	*session = (struct rewrite_session *)v_session;
   314→
   315→#ifdef USE_REWRITE_LDAP_PVT_THREADS
   316→	ldap_pvt_thread_rdwr_wlock( &session->ls_vars_mutex );
   317→#endif /* USE_REWRITE_LDAP_PVT_THREADS */
   318→
   319→	rewrite_var_delete( session->ls_vars );
   320→
   321→#ifdef USE_REWRITE_LDAP_PVT_THREADS
   322→	ldap_pvt_thread_rdwr_wunlock( &session->ls_vars_mutex );
   323→	ldap_pvt_thread_rdwr_destroy( &session->ls_vars_mutex );
   324→	ldap_pvt_thread_mutex_unlock( &session->ls_mutex );
   325→	ldap_pvt_thread_mutex_destroy( &session->ls_mutex );
   326→#endif /* USE_REWRITE_LDAP_PVT_THREADS */
   327→}
   328→
   329→static void
   330→rewrite_session_free( void *v_session )
   331→{
   332→	struct rewrite_session	*session = (struct rewrite_session *)v_session;
   333→
   334→#ifdef USE_REWRITE_LDAP_PVT_THREADS
   335→	ldap_pvt_thread_mutex_lock( &session->ls_mutex );
   336→#endif /* USE_REWRITE_LDAP_PVT_THREADS */
   337→	rewrite_session_clean( v_session );
   338→	free( v_session );
   339→}
   340→
   341→/*
   342→ * Deletes a session
   343→ */
   344→int
   345→rewrite_session_delete(
   346→		struct rewrite_info *info,
   347→		const void *cookie
   348→)
   349→{
   350→	struct rewrite_session *session, tmp = { 0 };
   351→
   352→	assert( info != NULL );
   353→	assert( cookie != NULL );
   354→
   355→	session = rewrite_session_find( info, cookie );
   356→
   357→	if ( session == NULL ) {
   358→		return REWRITE_SUCCESS;
   359→	}
   360→
   361→	if ( --session->ls_count > 0 ) {
   362→		rewrite_session_return( info, session );
   363→		return REWRITE_SUCCESS;
   364→	}
   365→
   366→	rewrite_session_clean( session );
   367→
   368→#ifdef USE_REWRITE_LDAP_PVT_THREADS
   369→	ldap_pvt_thread_rdwr_wlock( &info->li_cookies_mutex );
   370→#endif /* USE_REWRITE_LDAP_PVT_THREADS */
   371→
   372→	assert( info->li_num_cookies > 0 );
   373→	info->li_num_cookies--;
   374→	
   375→	/*
   376→	 * There is nothing to delete in the return value
   377→	 */
   378→	tmp.ls_cookie = ( void * )cookie;
   379→	ldap_avl_delete( &info->li_cookies, ( caddr_t )&tmp, rewrite_cookie_cmp );
   380→
   381→	free( session );
   382→
   383→#ifdef USE_REWRITE_LDAP_PVT_THREADS
   384→	ldap_pvt_thread_rdwr_wunlock( &info->li_cookies_mutex );
   385→#endif /* USE_REWRITE_LDAP_PVT_THREADS */
   386→
   387→	return REWRITE_SUCCESS;
   388→}
   389→
   390→/*
   391→ * Destroys the cookie tree
   392→ */
   393→int
   394→rewrite_session_destroy(
   395→		struct rewrite_info *info
   396→)
   397→{
   398→	int count;
   399→
   400→	assert( info != NULL );
   401→	
   402→#ifdef USE_REWRITE_LDAP_PVT_THREADS
   403→	ldap_pvt_thread_rdwr_wlock( &info->li_cookies_mutex );
   404→#endif /* USE_REWRITE_LDAP_PVT_THREADS */
   405→
   406→	/*
   407→	 * Should call per-session destruction routine ...
   408→	 */
   409→	
   410→	count = ldap_avl_free( info->li_cookies, rewrite_session_free );
   411→	info->li_cookies = NULL;
   412→
   413→#if 0
   414→	fprintf( stderr, "count = %d; num_cookies = %d\n", 
   415→			count, info->li_num_cookies );
   416→#endif
   417→	
   418→	assert( count == info->li_num_cookies );
   419→	info->li_num_cookies = 0;
   420→
   421→#ifdef USE_REWRITE_LDAP_PVT_THREADS
   422→	ldap_pvt_thread_rdwr_wunlock( &info->li_cookies_mutex );
   423→#endif /* USE_REWRITE_LDAP_PVT_THREADS */
   424→
   425→	return REWRITE_SUCCESS;
   426→}
